#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    void solve(vector<int>& nums) {
        if (nums.size() == 0) return;
        int prev = nums[0];
        for (int i = 1; i < nums.size(); i++) {
            if (nums[i] != prev) {
                cout << nums[i] << ' '; // print elements if no duplicates found
                prev = nums[i];
            }
        }
    }

};

int main() {
    Solution solution;
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    solution.solve(nums);
    cout << endl;
    return 0;
}
